// esbuild's dataurl loader turns `import x from './file.png'` into a base64
// data URI string at build time. TypeScript has no built-in declaration for
// binary imports, so declare a permissive default export here.
declare module '*.png' {
  const src: string;
  export default src;
}
declare module '*.svg' {
  const src: string;
  export default src;
}
declare module '*.jpg' {
  const src: string;
  export default src;
}
declare module '*.jpeg' {
  const src: string;
  export default src;
}
declare module '*.gif' {
  const src: string;
  export default src;
}
declare module '*.webp' {
  const src: string;
  export default src;
}
